import React, { useState, useEffect } from 'react';
import axios from 'axios';
import API_BASE from '../config';
import CardDisplay from './CardDisplay';
import { getOptimizedCardImageUrl, getCardFallbackImage } from '../utils/imageUtils';

function DeckBuilder() {
  const [firstName, setFirstName] = useState('');
  const [lastName, setLastName] = useState('');
  const [handle, setHandle] = useState('');
  const [platform, setPlatform] = useState('Whatnot');
  const [email, setEmail] = useState('');
  const [deckName, setDeckName] = useState('');
  const [character, setCharacter] = useState('');
  const [rarity, setRarity] = useState('Core');
  const [deck, setDeck] = useState([]);
  const [savedDecks, setSavedDecks] = useState([]);
  const [allCharacters, setAllCharacters] = useState([]);
  const [filteredCharacters, setFilteredCharacters] = useState([]);
  const [previewCard, setPreviewCard] = useState(null);
  const [hoveredCardIndex, setHoveredCardIndex] = useState(null);

  const rarityPoints = {
    "Core": 0,
    "Rare": 2,
    "Very Rare": 3,
    "Epic": 4,
    "Spectacular": 5
  };

  const platforms = [
    'Whatnot',
    'X',
    'LinkedIn',
    'YouTube',
    'Instagram',
    'TikTok',
    'Other'
  ];

  // VeeFriends-inspired styles with updated colors and fonts
  const styles = {
    container: {
      backgroundColor: '#3e0754', // Primary purple background
      minHeight: '100vh',
      padding: '20px',
      fontFamily: '"TradeGothicNextLTProBoldCompressed", "Trade Gothic Next", "Trebuchet MS", sans-serif',
      color: '#FFFFFF'
    },
    header: {
      color: '#e8b343', // Gold
      fontSize: '2.5rem',
      fontWeight: 'bold',
      textAlign: 'center',
      marginBottom: '2rem',
      textShadow: '2px 2px 4px rgba(0,0,0,0.3)',
      textTransform: 'uppercase'
    },
    section: {
      backgroundColor: '#300442', // Dark purple instead of white
      marginBottom: '20px',
      padding: '20px',
      borderRadius: '15px',
      border: '3px solid #e8b343', // Gold border
      boxShadow: '0 4px 8px rgba(0,0,0,0.2)'
    },
    sectionTitle: {
      color: '#e8b343', // Gold for better contrast on dark purple
      fontSize: '1.5rem',
      fontWeight: 'bold',
      marginBottom: '15px',
      textTransform: 'uppercase'
    },
    input: {
      padding: '10px',
      borderRadius: '8px',
      border: '2px solid #e8b343', // Gold border
      marginRight: '10px',
      marginBottom: '10px',
      fontFamily: 'inherit',
      fontSize: '14px',
      fontWeight: 'bold',
      backgroundColor: '#FFFFFF',
      color: '#000',
      textTransform: 'none' // Regular capitalization for form fields
    },
    button: {
      backgroundColor: '#e8b343', // Gold background
      color: '#000',
      border: '3px solid #000',
      borderRadius: '10px',
      padding: '12px 20px',
      fontSize: '16px',
      fontWeight: 'bold',
      cursor: 'pointer',
      boxShadow: '3px 3px 0px #000',
      transition: 'all 0.1s',
      fontFamily: 'inherit',
      textTransform: 'uppercase'
    },
    buttonHover: {
      transform: 'translate(2px, 2px)',
      boxShadow: '1px 1px 0px #000'
    },
    select: {
      padding: '10px',
      borderRadius: '8px',
      border: '2px solid #e8b343', // Gold border
      fontFamily: 'inherit',
      fontSize: '14px',
      fontWeight: 'bold',
      backgroundColor: '#FFFFFF',
      color: '#000',
      textTransform: 'none' // Regular capitalization for form fields
    },
    previewCard: {
      marginBottom: '20px',
      padding: '20px',
      border: '3px solid #10B981',
      borderRadius: '15px',
      background: '#065F46', // Darker green to match theme
      boxShadow: '0 4px 8px rgba(0,0,0,0.2)'
    },
    previewTitle: {
      color: '#10B981',
      fontWeight: 'bold',
      fontSize: '1.3rem',
      textTransform: 'uppercase'
    },
    deckGrid: {
      display: 'grid',
      gridTemplateColumns: 'repeat(auto-fill, minmax(120px, 1fr))',
      gap: '1rem',
      marginTop: '1rem'
    },
    cardContainer: {
      position: 'relative',
      cursor: 'pointer',
      transition: 'transform 0.2s',
      borderRadius: '8px',
      overflow: 'hidden'
    },
    cardImage: {
      width: '100%',
      height: 'auto',
      borderRadius: '8px',
      border: '2px solid #e8b343' // Gold border
    },
    cardName: {
      textAlign: 'center',
      fontWeight: 'bold',
      fontSize: '12px',
      marginTop: '5px',
      wordWrap: 'break-word',
      lineHeight: '1.2',
      color: '#FFFFFF',
      textTransform: 'uppercase'
    },
    trashIcon: {
      position: 'absolute',
      top: '5px',
      right: '5px',
      backgroundColor: 'rgba(220, 53, 69, 0.9)',
      color: 'white',
      border: 'none',
      borderRadius: '50%',
      width: '25px',
      height: '25px',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
      justifyContent: 'center',
      fontSize: '12px',
      opacity: 0,
      transition: 'opacity 0.2s'
    },
    autocomplete: {
      position: 'absolute',
      top: '100%',
      left: 0,
      right: 0,
      border: '2px solid #e8b343', // Gold border
      maxHeight: '150px',
      overflowY: 'scroll',
      backgroundColor: '#FFFFFF',
      borderRadius: '8px',
      marginTop: '5px',
      zIndex: 1000
    },
    autocompleteItem: {
      padding: '10px',
      cursor: 'pointer',
      borderBottom: '1px solid #E5E7EB',
      fontWeight: 'bold',
      color: '#000',
      textTransform: 'none' // Regular capitalization for form fields
    },
    addCardContainer: {
      display: 'flex',
      alignItems: 'flex-start',
      gap: '10px',
      flexWrap: 'wrap'
    },
    searchContainer: {
      position: 'relative',
      minWidth: '200px'
    },
    requiredText: {
      color: '#D1D5DB', // Light gray for better contrast on dark purple
      fontWeight: 'bold',
      textTransform: 'none' // Regular capitalization for form fields
    },
    savedDeckItem: {
      backgroundColor: '#3e0754', // Primary purple
      padding: '10px',
      marginBottom: '10px',
      borderRadius: '8px',
      border: '2px solid #e8b343', // Gold border
      display: 'flex',
      justifyContent: 'space-between',
      alignItems: 'center'
    },
    savedDeckText: {
      fontWeight: 'bold',
      color: '#FFFFFF',
      textTransform: 'none' // Regular capitalization for form fields
    },
    submitButton: {
      backgroundColor: '#e8b343', // Gold background
      color: '#000',
      border: '3px solid #000',
      borderRadius: '10px',
      fontSize: '18px',
      padding: '15px 30px',
      fontWeight: 'bold',
      cursor: 'pointer',
      boxShadow: '3px 3px 0px #000',
      transition: 'all 0.1s',
      fontFamily: 'inherit',
      textTransform: 'uppercase'
    },
    hr: {
      margin: '2rem 0',
      border: '2px solid #e8b343' // Gold
    }
  };

  useEffect(() => {
    const fetchCharacters = async () => {
      try {
        const res = await axios.get(`${API_BASE}/api/cards`);
        const names = res.data.map(c => c.character.toUpperCase());
        setAllCharacters(names);
      } catch (err) {
        console.error('Failed to fetch character list');
      }
    };
    fetchCharacters();
  }, []);

  const totalRarityPoints = deck.reduce((sum, card) => sum + rarityPoints[card.rarity], 0);

  const addCard = async () => {
    if (deck.length >= 20) return alert('Deck is full');
    if (deck.some(c => c.character === character)) return alert('Character already in deck');
    if (totalRarityPoints + rarityPoints[rarity] > 15) return alert('Not enough rarity points');
    if (!allCharacters.includes(character)) return alert('Invalid character name');

    // Fetch card details for preview and deck
    try {
      console.log('Fetching cards from API...');
      const res = await axios.get(`${API_BASE}/api/cards`);
      console.log('API Response:', res.data);

      const cardData = res.data.find(c => c.character.toUpperCase() === character);
      console.log('Found card data:', cardData);
      console.log('Looking for character:', character);

      const newCard = { character, rarity, ...cardData };
      console.log('New card object:', newCard);

      setDeck([...deck, newCard]);
      setPreviewCard(newCard);
      setCharacter('');
      setFilteredCharacters([]);

      setTimeout(() => setPreviewCard(null), 5000);
    } catch (err) {
      console.error('Failed to fetch card data:', err);
      setDeck([...deck, { character, rarity }]);
      setCharacter('');
      setFilteredCharacters([]);
    }
  };

  const removeCard = (index) => {
    const updatedDeck = [...deck];
    updatedDeck.splice(index, 1);
    setDeck(updatedDeck);
  };

  const submitDeck = async () => {
    // Validate required fields
    if (!firstName.trim() || !handle.trim() || !email.trim() || !deckName.trim() || deck.length !== 20) {
      alert('Please fill all required fields (First Name, Handle, Email, Deck Name) and build a full deck.');
      return;
    }

    // Normalize email
    const normalizedEmail = email.trim().toLowerCase();

    const payload = {
      firstName: firstName.trim(),
      lastName: lastName.trim(),
      handle: handle.trim(),
      platform,
      email: normalizedEmail,
      name: deckName.trim(),
      cards: deck
    };

    try {
      await axios.post(`${API_BASE}/api/decks`, payload);
      alert('Deck submitted!');
    } catch (err) {
      console.error("Error saving deck:", err);
      alert('Failed to submit deck');
    }
  };

  const loadDecks = async () => {
    if (!email.trim()) {
      alert('Please enter your email to load saved decks.');
      return;
    }

    try {
      const normalizedEmail = email.trim().toLowerCase();
      const res = await axios.get(`${API_BASE}/api/decks?email=${normalizedEmail}`);
      setSavedDecks(res.data);
    } catch (err) {
      console.error(err);
      alert('Failed to load saved decks');
    }
  };

  const loadSelectedDeck = (cards) => {
    setDeck(cards);
  };

  const handleCharacterInput = (e) => {
    const input = e.target.value.toUpperCase();
    setCharacter(input);
    const matches = allCharacters.filter(name => name.includes(input));
    setFilteredCharacters(matches.slice(0, 10));
  };

  const handleCharacterSelect = (name) => {
    setCharacter(name);
    setFilteredCharacters([]);
  };

  return (
    <div style={styles.container}>
      <h1 style={styles.header}>🎮 Build Your VeeFriends Deck 🎮</h1>

      {/* User Information Section */}
      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>👤 User Information</h3>
        <div style={{ marginBottom: '10px' }}>
          <input
            type="text"
            placeholder="First Name *"
            value={firstName}
            onChange={e => setFirstName(e.target.value)}
            style={{ ...styles.input, width: '200px' }}
          />
          <input
            type="text"
            placeholder="Last Name"
            value={lastName}
            onChange={e => setLastName(e.target.value)}
            style={{ ...styles.input, width: '200px' }}
          />
        </div>
        <div style={{ marginBottom: '10px' }}>
          <input
            type="text"
            placeholder="Handle (Display Name) *"
            value={handle}
            onChange={e => setHandle(e.target.value)}
            style={{ ...styles.input, width: '200px' }}
          />
          <select 
            value={platform} 
            onChange={e => setPlatform(e.target.value)}
            style={{ ...styles.select, width: '120px' }}
          >
            {platforms.map(p => (
              <option key={p} value={p}>{p}</option>
            ))}
          </select>
        </div>
        <input
          type="email"
          placeholder="Email *"
          value={email}
          onChange={e => setEmail(e.target.value)}
          style={{ ...styles.input, width: '300px' }}
        />
        <br />
        <input
          type="text"
          placeholder="Deck Name *"
          value={deckName}
          onChange={e => setDeckName(e.target.value)}
          style={{ ...styles.input, width: '300px' }}
        />
        <br />
        <small style={styles.requiredText}>* Required fields</small>
      </div>

      {/* Preview Card - Show recently added card */}
      {previewCard && (
        <div style={styles.previewCard}>
          <h3 style={styles.previewTitle}>
            ✅ Card Added to Deck!
          </h3>
          <CardDisplay card={previewCard} size="medium" />
        </div>
      )}

      {/* Deck Building Section */}
      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>🃏 Add Cards to Deck</h3>
        <div style={styles.addCardContainer}>
          <div style={styles.searchContainer}>
            <input
              type="text"
              placeholder="Character name"
              value={character}
              onChange={handleCharacterInput}
              autoComplete="off"
              style={{ ...styles.input, width: '200px', marginRight: 0, marginBottom: 0 }}
            />
            {filteredCharacters.length > 0 && (
              <div style={styles.autocomplete}>
                {filteredCharacters.map((name, idx) => (
                  <div 
                    key={idx} 
                    onClick={() => handleCharacterSelect(name)} 
                    style={{
                      ...styles.autocompleteItem,
                      backgroundColor: idx % 2 === 0 ? '#F9FAFB' : '#FFFFFF'
                    }}
                    onMouseEnter={e => e.target.style.backgroundColor = '#e8b343'}
                    onMouseLeave={e => e.target.style.backgroundColor = idx % 2 === 0 ? '#F9FAFB' : '#FFFFFF'}
                  >
                    {name}
                  </div>
                ))}
              </div>
            )}
          </div>
          <select 
            value={rarity} 
            onChange={e => setRarity(e.target.value)}
            style={styles.select}
          >
            <option>Core</option>
            <option>Rare</option>
            <option>Very Rare</option>
            <option>Epic</option>
            <option>Spectacular</option>
          </select>
          <button 
            onClick={addCard}
            style={styles.button}
            onMouseEnter={e => Object.assign(e.target.style, styles.buttonHover)}
            onMouseLeave={e => {
              e.target.style.transform = 'none';
              e.target.style.boxShadow = '3px 3px 0px #000';
            }}
          >
            Add Card
          </button>
        </div>
      </div>

      {/* Enhanced Deck Display */}
      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>
          🎯 Current Deck ({deck.length}/20) | Rarity Points: {totalRarityPoints}/15
        </h3>

        <div style={styles.deckGrid}>
          {deck.map((card, idx) => {
            // Use the imageUtils to generate the proper Cloudinary URL
            const imageUrl = getOptimizedCardImageUrl(card, { width: 200, height: 280 });
            const fallbackUrl = getCardFallbackImage(card);

            console.log(`Card ${idx}:`, card);
            console.log(`Generated URL:`, imageUrl);

            return (
              <div 
                key={idx} 
                style={{
                  ...styles.cardContainer,
                  transform: hoveredCardIndex === idx ? 'scale(1.05)' : 'scale(1)'
                }}
                onMouseEnter={() => setHoveredCardIndex(idx)}
                onMouseLeave={() => setHoveredCardIndex(null)}
              >
                {imageUrl ? (
                  <img 
                    src={imageUrl} 
                    alt={card.character}
                    style={styles.cardImage}
                    onError={(e) => {
                      console.error('Primary image failed to load:', imageUrl);
                      console.log('Trying fallback:', fallbackUrl);
                      e.target.src = fallbackUrl;
                    }}
                  />
                ) : (
                  <div style={{
                    ...styles.cardImage,
                    height: '150px',
                    backgroundColor: '#E5E7EB',
                    display: 'flex',
                    alignItems: 'center',
                    justifyContent: 'center',
                    fontSize: '12px',
                    fontWeight: 'bold',
                    color: '#000'
                  }}>
                    No Image
                  </div>
                )}

                <div style={styles.cardName}>
                  {card.character}
                </div>

                {/* Trash icon that appears on hover */}
                <button 
                  onClick={() => removeCard(idx)}
                  style={{
                    ...styles.trashIcon,
                    opacity: hoveredCardIndex === idx ? 1 : 0
                  }}
                  title="Remove card"
                >
                  🗑️
                </button>
              </div>
            );
          })}
        </div>
      </div>

      <div style={{ textAlign: 'center', marginTop: '2rem' }}>
        <button 
          onClick={submitDeck}
          style={styles.submitButton}
          onMouseEnter={e => Object.assign(e.target.style, styles.buttonHover)}
          onMouseLeave={e => {
            e.target.style.transform = 'none';
            e.target.style.boxShadow = '3px 3px 0px #000';
          }}
        >
          🚀 Submit Deck
        </button>
      </div>

      <hr style={styles.hr} />

      <div style={styles.section}>
        <h3 style={styles.sectionTitle}>💾 Load Saved Decks</h3>
        <button 
          onClick={loadDecks}
          style={styles.button}
          onMouseEnter={e => Object.assign(e.target.style, styles.buttonHover)}
          onMouseLeave={e => {
            e.target.style.transform = 'none';
            e.target.style.boxShadow = '3px 3px 0px #000';
          }}
        >
          Load Saved Decks
        </button>
        {savedDecks.length > 0 && (
          <ul style={{ marginTop: '1rem', listStyle: 'none', padding: 0 }}>
            {savedDecks.map((d, i) => (
              <li key={i} style={styles.savedDeckItem}>
                <span style={styles.savedDeckText}>
                  {d.name} ({new Date(d.createdAt).toLocaleString()})
                </span>
                <button 
                  onClick={() => loadSelectedDeck(d.cards)}
                  style={{ ...styles.button, padding: '5px 10px', fontSize: '14px' }}
                  onMouseEnter={e => Object.assign(e.target.style, styles.buttonHover)}
                  onMouseLeave={e => {
                    e.target.style.transform = 'none';
                    e.target.style.boxShadow = '3px 3px 0px #000';
                  }}
                >
                  Load
                </button>
              </li>
            ))}
          </ul>
        )}
      </div>
    </div>
  );
}

export default DeckBuilder;
